9152   for (auto *ExitVPBB : Plan.getExitBlocks()) {
9153     for (auto *PredVPBB : ExitVPBB->getPredecessors()) {
9154       // If the predecessor is not the middle.block, then it must be the
9155       // vector.early.exit block, which may contain work to calculate the exit
9156       // values of variables used outside the loop.
