9167 /// This function determines whether or not it's still profitable to vectorize
9168 /// the loop given the extra work we have to do outside of the loop:
9169 ///  1. Perform the runtime checks before entering the loop to ensure it's safe
9170 ///     to vectorize.
9171 ///  2. In the case of loops with uncountable early exits, we may have to do
9172 ///     extra work when exiting the loop early, such as calculating the final
9173 ///     exit values of variables used outside the loop.
9174 ///  3. The middle block.
9175 static bool isOutsideLoopWorkProfitable(GeneratedRTChecks &Checks,
9176                                         VectorizationFactor &VF, Loop *L,
9177                                         PredicatedScalarEvolution &PSE,
9178                                         VPCostContext &CostCtx, VPlan &Plan,
9179                                         ScalarEpilogueLowering SEL,
9180                                         std::optional<unsigned> VScale) {
9181   InstructionCost RtC = Checks.getCost();
9182   if (!RtC.isValid())
9183     return false;
9184 
9185   // When interleaving only scalar and vector cost will be equal, which in turn
9186   // would lead to a divide by 0. Fall back to hard threshold.
9187   if (VF.Width.isScalar()) {
9188     // TODO: Should we rename VectorizeMemoryCheckThreshold?
9189     if (RtC > VectorizeMemoryCheckThreshold) {
9190       LLVM_DEBUG(
9191           dbgs()
9192           << "LV: Interleaving only is not profitable due to runtime checks\n");
9193       return false;
9194     }
9195     return true;
9196   }
9197 
9198   // The scalar cost should only be 0 when vectorizing with a user specified
9199   // VF/IC. In those cases, runtime checks should always be generated.
9200   uint64_t ScalarC = VF.ScalarCost.getValue();
9201   if (ScalarC == 0)
9202     return true;
9203 
9204   InstructionCost TotalCost = RtC;
9205   // Add on the cost of any work required in the vector early exit block, if
9206   // one exists.
9207   TotalCost += calculateEarlyExitCost(CostCtx, Plan, VF.Width);
9208   TotalCost += Plan.getMiddleBlock()->cost(VF.Width, CostCtx);
9209 
9210   // First, compute the minimum iteration count required so that the vector
9211   // loop outperforms the scalar loop.
9212   //  The total cost of the scalar loop is
9213   //   ScalarC * TC
9214   //  where
9215   //  * TC is the actual trip count of the loop.
9216   //  * ScalarC is the cost of a single scalar iteration.
9217   //
9218   //  The total cost of the vector loop is
9219   //    TotalCost + VecC * (TC / VF) + EpiC
9220   //  where
9221   //  * TotalCost is the sum of the costs cost of
9222   //    - the generated runtime checks, i.e. RtC
9223   //    - performing any additional work in the vector.early.exit block for
9224   //      loops with uncountable early exits.
9225   //    - the middle block, if ExpectedTC <=  VF.Width.
9226   //  * VecC is the cost of a single vector iteration.
9227   //  * TC is the actual trip count of the loop
9228   //  * VF is the vectorization factor
9229   //  * EpiCost is the cost of the generated epilogue, including the cost
9230   //    of the remaining scalar operations.
9231   //
9232   // Vectorization is profitable once the total vector cost is less than the
9233   // total scalar cost:
9234   //   TotalCost + VecC * (TC / VF) + EpiC <  ScalarC * TC
9235   //
9236   // Now we can compute the minimum required trip count TC as
9237   //   VF * (TotalCost + EpiC) / (ScalarC * VF - VecC) < TC
9238   //
9239   // For now we assume the epilogue cost EpiC = 0 for simplicity. Note that
9240   // the computations are performed on doubles, not integers and the result
9241   // is rounded up, hence we get an upper estimate of the TC.
9242   unsigned IntVF = estimateElementCount(VF.Width, VScale);
9243   uint64_t Div = ScalarC * IntVF - VF.Cost.getValue();
9244   uint64_t MinTC1 =
9245       Div == 0 ? 0 : divideCeil(TotalCost.getValue() * IntVF, Div);
9246 
9247   // Second, compute a minimum iteration count so that the cost of the
9248   // runtime checks is only a fraction of the total scalar loop cost. This
9249   // adds a loop-dependent bound on the overhead incurred if the runtime
9250   // checks fail. In case the runtime checks fail, the cost is RtC + ScalarC
